111-\begin{theorem}\leanok
112-[Cotangent exact sequence for a composition]
113-  \label{thm:cotangent_exact_sequence}
114-  \lean{AlgebraicGeometry.Scheme.cotangent_exact_sequence}
115:  \uses{def:relative_kaehler_sheaf, def:universal_derivation, def:cotangent_alpha, def:cotangent_beta, lem:cotangent_exact_structure}
116-  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is an exact sequence of quasi-coherent $\struct{X}$-modules
117-  \[
118-    f^*\Omega_{Y/S} \;\xrightarrow{\;\alpha\;}\; \Omega_{X/S} \;\xrightarrow{\;\beta\;}\;
119-      \Omega_{X/Y} \;\longrightarrow\; 0,
120-  \]
121:  with $\alpha$ and $\beta$ as above. It follows by bundling the three claims of Lemma~\ref{lem:cotangent_exact_structure}.
122-\end{theorem}
